<!DOCTYPE html>
<html>
<head>
  <style>
    body {
      background: #1a1a1a;
      color: #fff;
      font-family: sans-serif;
      display: flex;
      flex-direction: column;
      align-items: center;
      justify-content: center;
      height: 100vh;
      margin: 0;
    }
    canvas {
      border: 2px solid #fff;
    }
    #score {
      margin-top: 10px;
    }
  </style>
</head>
<body>
  <canvas id="snake"></canvas>
  <div>
    <button id="start">Start</button>
    <button id="pause">Pause</button>
    <button id="reset">Reset</button>
  </div>
  <div>Score: <span id="score">0</span></div>
  <script>
    const canvas = document.getElementById('snake');
    const ctx = canvas.getContext('2d');
    const cellSize = 40;
    const gridWidth = 10;
    const gridHeight = 10;
    let gameInterval = null;

    const game = {
      w: gridWidth,
      h: gridHeight,
      snake: [],
      direction: 'right',
      food: [0, 0],
      score: 0,
      alive: true,
      reset() {
        this.snake = [
          [5,5], [4,5], [3,5]
        ];
        this.direction = 'right';
        this.score = 0;
        this.alive = true;
        this.placeFood();
        this.draw();
        document.getElementById('score').textContent = this.score;
      },
      placeFood() {
        let x, y;
        do {
          x = Math.floor(Math.random() * this.w);
          y = Math.floor(Math.random() * this.h);
        } while (this.snake.some(segment => segment[0] === x && segment[1] === y));
        this.food = [x, y];
      },
      setDir(dir) {
        const opposite = {
          'up': 'down',
          'down': 'up',
          'left': 'right',
          'right': 'left'
        };
        if (this.direction === opposite[dir]) return;
        this.direction = dir;
      },
      tick() {
        if (!this.alive) return;
        const head = this.snake[0];
        let newHead;
        switch (this.direction) {
          case 'up': newHead = [head[0], head[1] - 1]; break;
          case 'down': newHead = [head[0], head[1] + 1]; break;
          case 'left': newHead = [head[0] - 1, head[1]]; break;
          case 'right': newHead = [head[0] + 1, head[1]]; break;
        }
        // Check wall collision
        if (newHead[0] < 0 || newHead[0] >= this.w || newHead[1] < 0 || newHead[1] >= this.h) {
          this.alive = false;
          return;
        }
        const isEating = newHead[0] === this.food[0] && newHead[1] === this.food[1];
        // Check self collision
        if (isEating) {
          if (this.snake.some(segment => segment[0] === newHead[0] && segment[1] === newHead[1])) {
            this.alive = false;
            return;
          }
        } else {
          if (this.snake.slice(0, -1).some(segment => segment[0] === newHead[0] && segment[1] === newHead[1])) {
            this.alive = false;
            return;
          }
        }
        // Move snake
        this.snake.unshift(newHead);
        if (isEating) {
          this.score++;
          document.getElementById('score').textContent = this.score;
          this.placeFood();
        } else {
          this.snake.pop();
        }
        this.draw();
      },
      draw() {
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        ctx.fillStyle = '#00ff00';
        this.snake.forEach(segment => {
          ctx.fillRect(segment[0] * cellSize, segment[1] * cellSize, cellSize, cellSize);
        });
        ctx.fillStyle = '#ff0000';
        ctx.fillRect(this.food[0] * cellSize, this.food[1] * cellSize, cellSize, cellSize);
      },
      snake() { return this.snake; },
      food() { return this.food; },
      alive() { return this.alive; },
      score() { return this.score; },
      setFood(x, y) {
        this.food = [x, y];
        this.draw();
      }
    };

    window.game = game;

    document.getElementById('start').addEventListener('click', () => {
      if (!gameInterval) {
        gameInterval = setInterval(() => game.tick(), 100);
      }
    });

    document.getElementById('pause').addEventListener('click', () => {
      if (gameInterval) {
        clearInterval(gameInterval);
        gameInterval = null;
      }
    });

    document.getElementById('reset').addEventListener('click', () => {
      if (gameInterval) {
        clearInterval(gameInterval);
        gameInterval = null;
      }
      game.reset();
    });

    document.addEventListener('keydown', (e) => {
      if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.key)) {
        e.preventDefault();
        if (!game.alive) return;
        switch (e.key) {
          case 'ArrowUp': game.setDir('up'); break;
          case 'ArrowDown': game.setDir('down'); break;
          case 'ArrowLeft': game.setDir('left'); break;
          case 'ArrowRight': game.setDir('right'); break;
        }
      }
    });

    window.onload = () => {
      canvas.width = 400;
      canvas.height = 400;
      game.reset();
    };
  </script>
</body>
</html>
